struct SSLContext {
    bool check_hostname = true;
    int verify_mode = 2; // 2 represents CERT_REQUIRED
};

void assert_raises(std::function<void()> fn) {
    try {
        fn();
    } catch (...) {
        return;
    }
    throw std::runtime_error("Expected exception was not thrown");
}

SSLContext getSSLContext() {
    SSLContext ctx;

    // Ensure certificate verification is enabled
    if (ctx.verify_mode == 0) { // 0 represents CERT_NONE
        throw std::invalid_argument("Certificate verification is disabled");
    }

    ctx.check_hostname = true;
    ctx.verify_mode = 2; // CERT_REQUIRED

    if (!ctx.check_hostname || ctx.verify_mode != 2) {
        throw std::runtime_error("SSL context configuration failed");
    }

    return ctx;
}

int main() {
    // Test that invalid arguments are rejected
    assert_raises([]() { getSSLContext(1); });
    assert_raises([]() { getSSLContext(nullptr); });
    assert_raises([]() { getSSLContext("x"); });

    // Test valid call
    SSLContext ctx = getSSLContext();
    if (!ctx.check_hostname || ctx.verify_mode != 2) {
        return 1;
    }

    return 0;
}

